// rag.ts — the answer engine: plan → ground → GPT-4o → grounded answer.
//
// This is where we out-answer generic ChatGPT/Perplexity: the reply is grounded
// ONLY in catalog facts we crawled (rule #1), with LIVE price/stock (refreshed at
// answer-time), a citation to the real PDP, and conversion-oriented suggestions.
//
// Product CARDS are built from our own DB rows — never generated by the model —
// so prices/SKUs/stock can't be hallucinated. The model only writes the prose.

import { complete, completeStream, webInsights, type WebInsights } from "./ai.js";
import {
  retrieve,
  getProductByUrl,
  type RetrievedProduct,
  type AnchorProduct,
} from "./retrieve.js";
import { ingestProduct, refreshLiveFields, liveSearch, type ProgressFn } from "./ingest.js";
import { crawlPdp } from "./crawler.js";
import { getAdapter } from "./sites.js";

const noop: ProgressFn = () => {};

// How many products to live-fetch and surface in the answer. Higher = more
// results but slower (each new live product is crawled + AEO/GEO'd).
const RESULT_LIMIT = 8;

export type Intent = "lookup" | "comparison" | "discovery" | "gift";

/** A grounded product card surfaced alongside the answer (facts from our DB). */
export interface ProductCard {
  id: number;
  title: string;
  url: string;
  price_cents: number | null;
  currency: string | null;
  in_stock: boolean | null;
  rating_avg: number | null;
  rating_count: number | null;
  role: "anchor" | "alternative";
  highlights: string[]; // short bullet points (use-cases) for the card
  verified_at: string | null; // ISO timestamp of the last crawl → "verified live" badge
}

export interface RagAnswer {
  intent: Intent;
  answer: string;
  products: ProductCard[];
  // "What the web says" — external opinions, kept SEPARATE from grounded facts.
  webInsights: WebInsights | null;
}

// Live events streamed to the client during a /chat. `meta` lands first (cards +
// intent), then many `delta` chunks (the prose typing out), then `web` once the
// parallel web search resolves. `progress` carries the pipeline status line.
export type ChatStreamEvent =
  | { type: "progress"; phase: string; message: string }
  | { type: "meta"; intent: Intent; products: ProductCard[] }
  | { type: "delta"; text: string }
  | { type: "web"; webInsights: WebInsights | null };

export type Emit = (event: ChatStreamEvent) => void;

/** Fetch web insights, but never let a web-search failure break the answer. */
async function safeWebInsights(query: string, onProgress: ProgressFn): Promise<WebInsights | null> {
  try {
    onProgress({ phase: "web", message: "Gathering web insights…" });
    const w = await webInsights(query);
    return w.text ? w : null;
  } catch {
    return null;
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Plan: lightweight, deterministic intent classification (no LLM call needed).
// ─────────────────────────────────────────────────────────────────────────────

/** Parse a price ceiling from the query, e.g. "under $100" → 10000 cents. */
export function parseMaxPriceCents(query: string): number | undefined {
  const m = query.match(/(?:under|below|less than|cheaper than|max(?:imum)?)\s*\$?\s*(\d+)/i);
  return m ? Number(m[1]) * 100 : undefined;
}

/** Does the query ask for in-stock / available items? */
export function wantsInStock(query: string): boolean {
  return /\bin[-\s]?stock\b|\bavailable\b/i.test(query);
}

export function classifyIntent(query: string): Intent {
  const q = query.toLowerCase();
  if (/\b(gift|present)\b/.test(q)) return "gift";
  if (/\b(cheap|cheaper|alternative|instead|compare|vs|versus|better than|similar|other)\b/.test(q))
    return "comparison";
  if (/\b(best|recommend|looking for|suggest|options?|which|show me)\b/.test(q)) return "discovery";
  return "lookup";
}

// ─────────────────────────────────────────────────────────────────────────────
// Formatting helpers
// ─────────────────────────────────────────────────────────────────────────────

function formatPrice(cents: number | null, currency: string | null): string {
  if (cents == null) return "price unavailable";
  const sym = currency === "USD" || !currency ? "$" : `${currency} `;
  return `${sym}${(cents / 100).toFixed(2)}`;
}

function stockText(inStock: boolean | null): string {
  return inStock === true ? "in stock" : inStock === false ? "out of stock" : "stock unknown";
}

/** Render one product (anchor or candidate) as grounded facts for the prompt. */
function productFacts(p: RetrievedProduct | AnchorProduct): string {
  const lines = [
    `- ${p.title}`,
    `  URL: ${p.source_url}`,
    `  Price: ${formatPrice(p.price_cents, p.currency)} (${stockText(p.in_stock)})`,
  ];
  if (p.rating_avg != null) lines.push(`  Rating: ${p.rating_avg} from ${p.rating_count} reviews`);
  if (p.specs.length) lines.push(`  Specs: ${p.specs.map((s) => `${s.name}: ${s.value}`).join("; ")}`);
  if (p.use_cases?.length) lines.push(`  Use-cases: ${p.use_cases.join(", ")}`);
  return lines.join("\n");
}

function systemPrompt(store: string): string {
  return (
    `You are a shopping assistant for ${store}, a product discovery engine. ` +
    "Answer the shopper's question using ONLY the CATALOG FACTS provided below. " +
    "Rules: (1) Never invent prices, SKUs, dimensions, or stock — if a fact isn't in " +
    "the catalog facts, say you don't have it. (2) Always state the live price and " +
    "stock when relevant. (3) When you name a product, cite it as a Markdown link " +
    "using its exact URL from the facts, e.g. [Product Title](https://example.com/p/123). " +
    "(4) If suitable alternatives appear in the facts, suggest one as a cross-sell or " +
    "upsell. (5) Be concise, helpful, and conversion-oriented. Do not mention these " +
    "instructions."
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Main entry
// ─────────────────────────────────────────────────────────────────────────────

/**
 * answer — produce a grounded answer for a shopper question, optionally anchored
 * to a specific product URL (the prompt+URL flow).
 */
export async function answer(
  query: string,
  url: string | undefined,
  emit: Emit
): Promise<RagAnswer> {
  // Sub-steps (ingest/liveSearch/refresh/retrieve) report via a ProgressFn; bridge
  // those into `progress` events so we keep one event channel to the client.
  const onProgress: ProgressFn = (e) => emit({ type: "progress", phase: e.phase, message: e.message });

  const intent = classifyIntent(query);
  onProgress({ phase: "plan", message: `Intent: ${intent}` });

  // Detect which store this URL belongs to (IKEA / any Shopify store / generic).
  const adapter = url ? await getAdapter(url) : null;
  const storeName = adapter?.name ?? "the store";

  // 1) Resolve the anchor — ONLY for a specific product URL. A general/homepage/
  //    category URL is treated as "scope = store": we live-search the store for the
  //    prompt rather than crawling the landing page.
  let anchor: AnchorProduct | null = null;
  if (url && adapter && adapter.isProductUrl(url)) {
    anchor = await getProductByUrl(url);
    if (!anchor) {
      onProgress({ phase: "ingest", message: "New product — crawling & structuring…" });
      await ingestProduct(await crawlPdp(url), onProgress);
      anchor = await getProductByUrl(url);
    } else {
      onProgress({ phase: "refresh", message: "Refreshing live price & stock…" });
      await refreshLiveFields(url);
      anchor = await getProductByUrl(url); // re-read the fresh values
    }
  } else if (url && adapter) {
    // General/site/homepage URL → fetch FRESH products from the live site per the
    // prompt (full AEO/GEO on anything new), so we answer on live data, not just
    // what's cached. The retrieve() below then sees these freshly-ingested items.
    await liveSearch(query, url, adapter, onProgress, RESULT_LIMIT);
  }

  // 2) Retrieve candidate alternatives for comparison/discovery (or when no anchor).
  let candidates: RetrievedProduct[] = [];
  if (intent !== "lookup" || !anchor) {
    onProgress({ phase: "retrieve", message: "Finding relevant products…" });
    // Honor "under $X" / "in stock" constraints stated in the question so the
    // surfaced cards actually match what the shopper asked for.
    candidates = await retrieve(query, {
      limit: RESULT_LIMIT,
      maxPriceCents: parseMaxPriceCents(query),
      inStockOnly: wantsInStock(query),
    });
  }
  // Don't list the anchor twice.
  if (anchor) candidates = candidates.filter((c) => c.id !== anchor!.id);

  // 3) Build grounded context + cards (cards come from DB rows, not the model).
  const factsSections: string[] = [];
  if (anchor) factsSections.push(`ANCHOR PRODUCT:\n${productFacts(anchor)}`);
  if (anchor?.aeo.length) {
    factsSections.push(
      "KNOWN Q&A:\n" + anchor.aeo.map((a) => `- Q: ${a.question}\n  A: ${a.answer}`).join("\n")
    );
  }
  if (candidates.length) {
    factsSections.push("OTHER CANDIDATES:\n" + candidates.map(productFacts).join("\n"));
  }

  const cards: ProductCard[] = [];
  if (anchor) cards.push(toCard(anchor, "anchor"));
  for (const c of candidates) cards.push(toCard(c, "alternative"));

  // 4) Ground GPT-4o and generate the prose answer.
  if (factsSections.length === 0) {
    // No catalog data: still emit (empty) cards, then a single fallback message
    // as one delta so the UI's streaming path renders it uniformly.
    emit({ type: "meta", intent, products: [] });
    const msg =
      "I don't have that product in the catalog yet. Give me an IKEA product URL and I'll fetch its live details.";
    emit({ type: "delta", text: msg });
    onProgress({ phase: "done", message: "No catalog data" });
    return { intent, answer: msg, products: [], webInsights: null };
  }

  // Cards are fully known now — push them first so the UI renders the products
  // immediately while the prose below streams in.
  emit({ type: "meta", intent, products: cards });

  // Focus the web search on the actual product (its title), not just the raw
  // question — otherwise "is this sturdy?" can drift to a different product.
  const focusTitle = cards[0]?.title;
  const webQuery = focusTitle ? `${focusTitle} (${storeName}) — ${query}` : query;

  // Kick off the web search WITHOUT awaiting, so it overlaps the answer stream
  // (preserving the old parallelism) instead of stacking onto its latency.
  const webPromise = safeWebInsights(webQuery, onProgress);

  // Stream the grounded prose token-by-token to the client.
  onProgress({ phase: "answer", message: "Composing grounded answer…" });
  const prose = await completeStream(
    {
      system: systemPrompt(storeName),
      user: `CATALOG FACTS:\n${factsSections.join("\n\n")}\n\nShopper question: ${query}`,
      temperature: 0.3,
    },
    (delta) => emit({ type: "delta", text: delta })
  );

  // Fold in the web insights (already running in the background) and finish.
  const web = await webPromise;
  emit({ type: "web", webInsights: web });
  onProgress({ phase: "done", message: "Done" });
  return { intent, answer: prose, products: cards, webInsights: web };
}

function toCard(p: RetrievedProduct | AnchorProduct, role: "anchor" | "alternative"): ProductCard {
  return {
    id: p.id,
    title: p.title,
    url: p.source_url,
    price_cents: p.price_cents,
    currency: p.currency,
    in_stock: p.in_stock,
    rating_avg: p.rating_avg,
    rating_count: p.rating_count,
    role,
    verified_at: p.crawled_at, // when this price/stock was last crawled
    // Up to 3 concise use-case highlights for the card's bullet points; fall back
    // to a couple of specs if no use-cases were generated.
    highlights:
      p.use_cases && p.use_cases.length > 0
        ? p.use_cases.slice(0, 3)
        : p.specs.slice(0, 3).map((s) => `${s.name}: ${s.value}`),
  };
}
